import React, { useState } from 'react';
import { Product } from '../types';

interface Review {
  id: number;
  user: string;
  time: string;
  content: string;
  product: string;
  reply?: string;
}

const mockReviews: Review[] = [
  {
    id: 1,
    user: 'Sol****',
    time: '2시간전',
    content: '진행 과정도 결과도 만족합니다. 그리고 문의에 친절하게 설명해주십니다.',
    product: '유튜브 구독자,조회수,쇼츠,시청시간,수익창출,스트리밍',
    reply: '소중한 후기를 남겨주셔서 진심으로 감사드립니다. 애드모어는 최상의 결과를 제공하기 위해 끊임없이 노력하고 있습니다. 앞으로도 한 걸음 더 나아가 최고의 서비스를 제공하기 위해 최선을 다하겠습니다. 함께 만들어가는 이 여정에 함께해 주셔서 감사합니다.'
  },
  {
    id: 2,
    user: '살*****',
    time: '20시간전',
    content: '친절하게 잘 설명해주시고 바로바로 피드백 주셔서 너무 좋습니다!',
    product: '애드모어',
    reply: '소중한 후기를 남겨주셔서 진심으로 감사드립니다. 애드모어는 최상의 결과를 제공하기 위해 끊임없이 노력하고 있습니다. 앞으로도 한 걸음 더 나아가 최고의 서비스를 제공하기 위해 최선을 다하겠습니다. 함께 만들어가는 이 여정에 함께해 주셔서 감사합니다.'
  },
  {
    id: 3,
    user: 'K31***',
    time: '하루전',
    content: '수고하셨습니다. 감사합니다.',
    product: '인스타그램 팔로워,릴스,좋아요,조회수,인기게시물 관리',
    reply: '소중한 후기를 남겨주셔서 진심으로 감사드립니다. 애드모어는 최상의 결과를 제공하기 위해 끊임없이 노력하고 있습니다. 앞으로도 한 걸음 더 나아가 최고의 서비스를 제공하기 위해 최선을 다하겠습니다. 함께 만들어가는 이 여정에 함께해 주셔서 감사합니다.'
  },
  {
    id: 4,
    user: '방**',
    time: '하루전',
    content: '빠른 대응과 기대이상의 결과물로 매우 만족 합니다.',
    product: '유튜브 구독자,조회수,쇼츠,시청시간,수익창출,스트리밍',
    reply: '소중한 후기를 남겨주셔서 진심으로 감사드립니다. 애드모어는 최상의 결과를 제공하기 위해 끊임없이 노력하고 있습니다. 앞으로도 한 걸음 더 나아가 최고의 서비스를 제공하기 위해 최선을 다하겠습니다. 함께 만들어가는 이 여정에 함께해 주셔서 감사합니다.'
  },
  {
    id: 5,
    user: '에*****',
    time: '2025-06-28',
    content: '항상 작업물의 퀄리티, 속도와 처리가 매우 만족을 줍니다. 대응도 신속하고 빠르며 친절한 설명에 많은 도움이 됩니다. 다음에 또 구매하겠습니다. 감사합니다.',
    product: '유튜브 구독자,조회수,쇼츠,시청시간,수익창출,스트리밍',
  },
];

const sortOptions = [
  { value: 'latest', label: '최신순' },
  { value: 'high', label: '평점 높은 순' },
  { value: 'low', label: '평점 낮은 순' },
];

const Reviews: React.FC = () => {
  const [activeTab, setActiveTab] = useState<string>('favorites');
  const [recentProducts, setRecentProducts] = useState<Product[]>([]);
  const [sort, setSort] = useState('latest');

  // Mock data for favorites
  const favorites: Product[] = [
    {
      id: 1,
      name: '페이스북 팔로워 1000명',
      price: '50,000원',
      category: '페이스북',
      image: 'https://via.placeholder.com/200x150?text=Facebook',
      addedDate: '2024-01-15'
    },
    {
      id: 2,
      name: '인스타그램 팔로워 500명',
      price: '30,000원',
      category: '인스타그램',
      image: 'https://via.placeholder.com/200x150?text=Instagram',
      addedDate: '2024-01-10'
    },
    {
      id: 3,
      name: '유튜브 구독자 1000명',
      price: '100,000원',
      category: '유튜브',
      image: 'https://via.placeholder.com/200x150?text=YouTube',
      addedDate: '2024-01-08'
    },
    {
      id: 4,
      name: '블로그 방문자 5000명',
      price: '80,000원',
      category: '블로그',
      image: 'https://via.placeholder.com/200x150?text=Blog',
      addedDate: '2024-01-05'
    }
  ];

  const handleRemoveFavorite = (id: number): void => {
    // Here you would typically remove the item from favorites
    console.log('Removing favorite:', id);
    alert('즐겨찾기에서 제거되었습니다.');
  };

  const handleRemoveAllFavorites = (): void => {
    if (window.confirm('모든 즐겨찾기를 삭제하시겠습니까?')) {
      // Here you would typically clear all favorites
      console.log('Clearing all favorites');
      alert('모든 즐겨찾기가 삭제되었습니다.');
    }
  };

  const handleRemoveAllRecent = (): void => {
    if (window.confirm('모든 최근 본 상품을 삭제하시겠습니까?')) {
      // Here you would typically clear all recent products
      console.log('Clearing all recent products');
      alert('모든 최근 본 상품이 삭제되었습니다.');
    }
  };

  // 실제 정렬 로직은 생략 (mock 데이터)
  const reviews = mockReviews;

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Page Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-4">리뷰</h1>
          <p className="text-gray-600">즐겨찾기와 최근 본 상품을 관리하세요</p>
        </div>

        {/* Tabs */}
        <div className="bg-white rounded-lg shadow-md overflow-hidden">
          <div className="border-b border-gray-200">
            <nav className="flex">
              <button
                onClick={() => setActiveTab('favorites')}
                className={`px-6 py-4 text-sm font-medium ${
                  activeTab === 'favorites'
                    ? 'border-b-2 border-blue-600 text-blue-600'
                    : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                즐겨찾기
              </button>
              <button
                onClick={() => setActiveTab('recent')}
                className={`px-6 py-4 text-sm font-medium ${
                  activeTab === 'recent'
                    ? 'border-b-2 border-blue-600 text-blue-600'
                    : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                최근 본
              </button>
            </nav>
          </div>

          {/* Tab Content */}
          <div className="p-6">
            {activeTab === 'favorites' && (
              <div>
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-lg font-semibold text-gray-900">즐겨찾기</h3>
                  {favorites.length > 0 && (
                    <button
                      onClick={handleRemoveAllFavorites}
                      className="text-red-600 hover:text-red-700 text-sm font-medium"
                    >
                      전체 삭제
                    </button>
                  )}
                </div>

                {favorites.length === 0 ? (
                  <div className="text-center py-12">
                    <div className="text-gray-400 mb-4">
                      <svg className="mx-auto h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                      </svg>
                    </div>
                    <p className="text-gray-500 text-lg">즐겨찾기한 상품이 없습니다.</p>
                    <p className="text-gray-400 text-sm mt-2">상품을 즐겨찾기에 추가해보세요.</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {favorites.map((product) => (
                      <div key={product.id} className="bg-white border border-gray-200 rounded-lg overflow-hidden hover:shadow-md transition duration-300">
                        <div className="relative">
                          <img src={product.image} alt={product.name} className="w-full h-48 object-cover" />
                          <button
                            onClick={() => handleRemoveFavorite(product.id)}
                            className="absolute top-2 right-2 bg-red-500 text-white p-1 rounded-full hover:bg-red-600 transition duration-300"
                          >
                            <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                            </svg>
                          </button>
                        </div>
                        <div className="p-4">
                          <div className="flex items-center justify-between mb-2">
                            <span className="text-xs text-gray-500 bg-gray-100 px-2 py-1 rounded">
                              {product.category}
                            </span>
                            <span className="text-xs text-gray-500">{product.addedDate}</span>
                          </div>
                          <h3 className="font-semibold text-gray-900 mb-2">{product.name}</h3>
                          <p className="text-blue-600 font-bold">{product.price}</p>
                          <div className="mt-3 space-y-2">
                            <button className="w-full bg-blue-600 text-white py-2 rounded-md hover:bg-blue-700 transition duration-300 text-sm">
                              구매하기
                            </button>
                            <button className="w-full border border-gray-300 text-gray-700 py-2 rounded-md hover:bg-gray-50 transition duration-300 text-sm">
                              장바구니
                            </button>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {activeTab === 'recent' && (
              <div>
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-lg font-semibold text-gray-900">최근 본 상품</h3>
                  {recentProducts.length > 0 && (
                    <button
                      onClick={handleRemoveAllRecent}
                      className="text-red-600 hover:text-red-700 text-sm font-medium"
                    >
                      전체 삭제
                    </button>
                  )}
                </div>

                {recentProducts.length === 0 ? (
                  <div className="text-center py-12">
                    <div className="text-gray-400 mb-4">
                      <svg className="mx-auto h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                      </svg>
                    </div>
                    <p className="text-gray-500 text-lg">최근 본 상품이 없습니다.</p>
                    <p className="text-gray-400 text-sm mt-2">상품을 둘러보시면 여기에 표시됩니다.</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {recentProducts.map((product) => (
                      <div key={product.id} className="bg-white border border-gray-200 rounded-lg overflow-hidden hover:shadow-md transition duration-300">
                        <img src={product.image} alt={product.name} className="w-full h-48 object-cover" />
                        <div className="p-4">
                          <div className="flex items-center justify-between mb-2">
                            <span className="text-xs text-gray-500 bg-gray-100 px-2 py-1 rounded">
                              {product.category}
                            </span>
                            <span className="text-xs text-gray-500">{product.viewedDate}</span>
                          </div>
                          <h3 className="font-semibold text-gray-900 mb-2">{product.name}</h3>
                          <p className="text-blue-600 font-bold">{product.price}</p>
                          <div className="mt-3 space-y-2">
                            <button className="w-full bg-blue-600 text-white py-2 rounded-md hover:bg-blue-700 transition duration-300 text-sm">
                              구매하기
                            </button>
                            <button className="w-full border border-gray-300 text-gray-700 py-2 rounded-md hover:bg-gray-50 transition duration-300 text-sm">
                              장바구니
                            </button>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        {/* Recommendations */}
        <div className="mt-8">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">추천 상품</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {favorites.slice(0, 4).map((product) => (
              <div key={product.id} className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition duration-300">
                <img src={product.image} alt={product.name} className="w-full h-48 object-cover" />
                <div className="p-4">
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-xs text-gray-500 bg-gray-100 px-2 py-1 rounded">
                      {product.category}
                    </span>
                  </div>
                  <h3 className="font-semibold text-gray-900 mb-2">{product.name}</h3>
                  <p className="text-blue-600 font-bold">{product.price}</p>
                  <div className="mt-3 space-y-2">
                    <button className="w-full bg-blue-600 text-white py-2 rounded-md hover:bg-blue-700 transition duration-300 text-sm">
                      구매하기
                    </button>
                    <button className="w-full border border-gray-300 text-gray-700 py-2 rounded-md hover:bg-gray-50 transition duration-300 text-sm">
                      장바구니
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Sort */}
        <div className="flex justify-end mb-6">
          <select
            value={sort}
            onChange={e => setSort(e.target.value)}
            className="border border-gray-300 rounded px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            {sortOptions.map(opt => (
              <option key={opt.value} value={opt.value}>{opt.label}</option>
            ))}
          </select>
        </div>

        {/* Review List */}
        <div className="space-y-8">
          {reviews.map(review => (
            <div key={review.id} className="bg-white rounded-lg shadow p-6">
              <div className="flex items-center mb-2">
                <span className="font-semibold text-blue-600 mr-2">{review.user}</span>
                <span className="text-xs text-gray-400">{review.time}</span>
              </div>
              <div className="mb-2 text-gray-900">{review.content}</div>
              <div className="text-xs text-gray-500 mb-2">{review.product}</div>
              {review.reply && (
                <div className="bg-gray-50 border-l-4 border-blue-400 p-3 text-sm text-gray-700 mt-2">
                  <span className="font-bold text-blue-600">애드모어</span> <span className="ml-2">{review.reply}</span>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Pagination (간단하게) */}
        <div className="flex justify-center mt-10">
          <button className="px-4 py-2 mx-1 bg-blue-100 text-blue-700 rounded">1</button>
          <button className="px-4 py-2 mx-1 bg-white border text-gray-700 rounded">2</button>
          <button className="px-4 py-2 mx-1 bg-white border text-gray-700 rounded">3</button>
          <span className="px-2 py-2 mx-1 text-gray-400">...</span>
          <button className="px-4 py-2 mx-1 bg-white border text-gray-700 rounded">123</button>
        </div>

        {/* 고객센터 & 회사 정보 (하단) */}
        <div className="mt-16 grid grid-cols-1 md:grid-cols-2 gap-8 text-sm text-gray-600">
          <div>
            <h3 className="font-bold text-gray-900 mb-2">고객센터</h3>
            <div>070-4580-7189</div>
            <div>11:00 ~ 17:00</div>
            <div>주말, 공휴일 휴무</div>
          </div>
          <div>
            <h3 className="font-bold text-gray-900 mb-2">회사 정보</h3>
            <div>주식회사 루트라보</div>
            <div>대표자 : 조병조</div>
            <div>경기도 용인시 기흥구 강남서로 9, 7 703호 K422호(구갈동)</div>
            <div>통신판매업신고 : 2022-서울강남-02565</div>
            <div>사업자등록번호 : 877-87-03261</div>
            <div>chojo@rootlabo.com</div>
          </div>
        </div>
      </div>
    </div>
  );
};

